// FLOW 3 — Consultant_Shortlist_Project_Rate_v0 — Code node: "Code in JavaScript"
// Fixes:
// 1) Correctly merges calc_* fields into output (use ...calc, not .calc)
// 2) Keeps shortlist + selected consultant pricing outputs
// 3) Adds small safety guards so missing fields don't crash the node

const SHORTLIST_SIZE = 5;
const TOPN_EXPOSED = 3;

// ---------- Helpers ----------
function levelNameToNum(name) {
  if (!name) return null;
  const n = String(name).toLowerCase();
  if (n.startsWith("junior")) return 1;
  if (n.startsWith("inter")) return 2;
  if (n.startsWith("senior")) return 3;
  if (n.startsWith("expert")) return 4;
  return null;
}

function parseCsv(str) {
  if (!str) return [];
  return String(str)
    .split(",")
    .map((s) => s.trim())
    .filter(Boolean);
}

function normaliseLang(l) {
  return String(l || "").trim().toLowerCase();
}

function computeFitScore(role, consultant) {
  let penalty = 0;

  // level mismatch penalty
  const roleLevelNum = levelNameToNum(role.role_level_required);
  const consLevelNum =
    consultant.level_id != null ? Number(consultant.level_id) : null;

  if (roleLevelNum != null && consLevelNum != null) {
    const diff = Math.abs(roleLevelNum - consLevelNum);
    if (diff === 1) penalty += 10;
    else if (diff === 2) penalty += 20;
    else if (diff >= 3) penalty += 30;
  }

  // skill area penalty (basic)
  const roleSkill = (role.role_skill_area || "").toLowerCase();
  if (roleSkill) {
    const primarySkill = (consultant.primary_skill_area || "").toLowerCase();
    const otherSkills = parseCsv(consultant.other_skill_areas || "").map((s) =>
      s.toLowerCase()
    );
    const inPrimary = primarySkill.includes(roleSkill);
    const inOther = otherSkills.some((s) => s.includes(roleSkill));
    if (!inPrimary && !inOther) penalty += 30;
  }

  // language penalty
  const roleLangs = parseCsv(role.role_languages_required);
  if (roleLangs.length) {
    const consLangs = parseCsv(consultant.languages_raw || "").map(normaliseLang);
    for (const required of roleLangs) {
      const reqNorm = normaliseLang(required);
      if (!reqNorm) continue;
      const hasLang =
        consLangs.includes(reqNorm) ||
        consLangs.some((l) => l.startsWith(reqNorm) || reqNorm.startsWith(l));
      if (!hasLang) penalty += 15;
    }
  }

  if (penalty < 0) penalty = 0;
  if (penalty > 80) penalty = 80;

  return { score: 100 - penalty };
}

function computeRateForPair(role, consultant, scarcityConf) {
  const baseMin =
    consultant.min_rate_indi != null ? Number(consultant.min_rate_indi) : 0;
  const baseMax =
    consultant.max_rate_indi != null ? Number(consultant.max_rate_indi) : 0;

  const baseSuggested =
    (consultant.suggested_rate_indi != null &&
      Number(consultant.suggested_rate_indi)) ||
    (consultant.average_rate_indi != null &&
      Number(consultant.average_rate_indi)) ||
    baseMin;

  let currency = "EUR";
  if (
    consultant.generic_rate_band &&
    typeof consultant.generic_rate_band === "object" &&
    consultant.generic_rate_band.currency
  ) {
    currency = consultant.generic_rate_band.currency;
  }

  if (!baseMin || !baseMax || baseMax <= baseMin) {
    return {
      error: "Invalid individual band",
      currency,
      baseMin,
      baseMax,
      baseSuggested,
      roleScIds: parseCsv(role.role_scarcity_ids || ""),
      consScIds: parseCsv(consultant.scarcity_ids_raw || ""),
      matchedScIds: [],
      scarcityUpliftMult: 1.0,
      scarcityUpliftMultCapped: 1.0,
      scarcityCapApplied: false,
      clientBuyingFactor: null,
      clientDefaultMargin: null,
      locationFactor: 1.0,
      buyRateRaw: null,
      buyRateClamped: null,
      buyRateClampReason: null,
      sellRate: null,
      days: null,
      budgetBuyTotal: null,
      budgetSellTotal: null,
      marginAbs: null,
      marginPctRealized: null,
    };
  }

  const roleScIds = parseCsv(role.role_scarcity_ids || "");
  const consScIds = [];

  if (consultant.scarcity_ids_raw) {
    consScIds.push(...parseCsv(consultant.scarcity_ids_raw));
  }
  if (consultant.is_economist && !consScIds.includes("ECON")) {
    consScIds.push("ECON");
  }

  const consSet = new Set(consScIds);
  const matchedScIds = roleScIds.filter((id) => consSet.has(id));

  // multiplicative uplift
  let scarcityUpliftMult = 1.0;
  for (const id of matchedScIds) {
    const cfg = scarcityConf.get(id);
    if (!cfg) continue;
    const u = Number(cfg.project_uplift_pct || 0); // expected decimal, e.g. 0.05
    scarcityUpliftMult *= 1 + u;
  }

  // cap to +20% (mult <= 1.2)
  let scarcityUpliftMultCapped = scarcityUpliftMult;
  let scarcityCapApplied = false;
  if (scarcityUpliftMultCapped > 1.2) {
    scarcityUpliftMultCapped = 1.2;
    scarcityCapApplied = true;
  }

  const clientBuyingFactor =
    role.client_buying_factor != null && role.client_buying_factor !== ""
      ? Number(role.client_buying_factor)
      : 1.0;

  const clientDefaultMargin =
    role.client_default_margin != null && role.client_default_margin !== ""
      ? Number(role.client_default_margin)
      : 0.2;

  const locationFactor = 1.0; // placeholder for now

  const buyRateRaw =
    baseSuggested * scarcityUpliftMultCapped * clientBuyingFactor * locationFactor;

  // clamp inside band
  let buyRateClamped = buyRateRaw;
  let buyRateClampReason = "NONE";
  if (buyRateClamped < baseMin) {
    buyRateClamped = baseMin;
    buyRateClampReason = "BELOW_MIN";
  } else if (buyRateClamped > baseMax) {
    buyRateClamped = baseMax;
    buyRateClampReason = "ABOVE_MAX";
  }

  const sellRate = buyRateClamped * (1 + clientDefaultMargin);
  const days =
    role.role_days != null && role.role_days !== "" ? Number(role.role_days) : 0;

  const budgetBuyTotal = buyRateClamped * days;
  const budgetSellTotal = sellRate * days;

  const marginAbs = budgetSellTotal - budgetBuyTotal;
  const marginPctRealized = budgetSellTotal > 0 ? marginAbs / budgetSellTotal : null;

  return {
    error: null,
    currency,
    baseMin,
    baseMax,
    baseSuggested,
    roleScIds,
    consScIds,
    matchedScIds,
    scarcityUpliftMult,
    scarcityUpliftMultCapped,
    scarcityCapApplied,
    clientBuyingFactor,
    clientDefaultMargin,
    locationFactor,
    buyRateRaw,
    buyRateClamped,
    buyRateClampReason,
    sellRate,
    days,
    budgetBuyTotal,
    budgetSellTotal,
    marginAbs,
    marginPctRealized,
  };
}

// ---------- Inputs ----------
const projectItems = $items("Get project roles");
const consultantItems = $items("Get Consultants");
const scarcityItems = $items("Get scarcity factors");

// ---------- Build consultants ----------
const consultants = [];
for (const item of consultantItems) {
  const row = item.json || {};
  const email = String(row.Email || row.email || "").trim();
  if (!email) continue;

  let genericBand = {};
  if (row.generic_rate_band) {
    try {
      genericBand = JSON.parse(row.generic_rate_band);
    } catch {
      genericBand = {};
    }
  }

  consultants.push({
    raw: row,
    name: row.Name || row.name || null,
    email,
    level_id:
      row.level_id != null && row.level_id !== "" ? Number(row.level_id) : null,
    level_label: row.level_label || row.level_key || null,
    primary_skill_area: row.primary_skill_area || "",
    other_skill_areas: row.other_skill_areas || "",
    languages_raw: row.languages || "",
    scarcity_ids_raw: row.scarcity_ids_auto || "",
    is_economist:
      String(row.is_economist || "").toLowerCase() === "true" || row.is_economist === true,
    generic_rate_band: genericBand,
    min_rate_indi:
      row.min_rate_indi != null && row.min_rate_indi !== "" ? Number(row.min_rate_indi) : 0,
    max_rate_indi:
      row.max_rate_indi != null && row.max_rate_indi !== "" ? Number(row.max_rate_indi) : 0,
    average_rate_indi:
      row.average_rate_indi != null && row.average_rate_indi !== "" ? Number(row.average_rate_indi) : 0,
    suggested_rate_indi:
      row.suggested_rate_indi != null && row.suggested_rate_indi !== "" ? Number(row.suggested_rate_indi) : 0,
  });
}

// ---------- Scarcity config map ----------
const scarcityConf = new Map();
for (const item of scarcityItems) {
  const row = item.json || {};
  const id = row.scarcity_id;
  if (!id) continue;
  const raw =
    row.project_uplift_pct != null && row.project_uplift_pct !== ""
      ? Number(row.project_uplift_pct)
      : 0;
  scarcityConf.set(id, {
    scarcity_id: id,
    project_uplift_pct: Number.isFinite(raw) ? raw : 0,
  });
}

// ---------- Process each role ----------
const out = [];

for (const item of projectItems) {
  const r = item.json || {};

  // n8n commonly uses row_number
  const rowNumber = r.row_number || r.rowNumber;
  if (!rowNumber) continue;

  const roleId = r.role_id;
  if (!roleId || String(roleId).trim() === "") continue;

  const consultantEmailRaw = String(r.consultant_email || "").trim();

  const role = {
    project_id: r.project_id,
    project_name: r.project_name,
    client_name_raw: r.client_name_raw,
    client_key: r.client_key,
    client_type: r.client_type,
    client_group: r.client_group,
    client_buying_factor: r.client_buying_factor,
    client_default_margin: r.client_default_margin,
    country: r.country,
    location_group: r.location_group,
    file_id: r.file_id,
    file_name: r.file_name,
    role_id: r.role_id,
    role_title: r.role_title,
    role_level_required: r.role_level_required,
    role_days: r.role_days,
    role_skill_area: r.role_skill_area,
    role_languages_required: r.role_languages_required,
    role_scarcity_ids: r.role_scarcity_ids,
  };

  // ---- Shortlist ----
  const shortlistCandidates = [];
  for (const cons of consultants) {
    const fit = computeFitScore(role, cons);
    const rateRes = computeRateForPair(role, cons, scarcityConf);

    shortlistCandidates.push({
      email: cons.email,
      name: cons.name,
      level_id: cons.level_id,
      level_label: cons.level_label,
      fit_score: fit.score,
      approx_buy_rate: rateRes.error ? null : rateRes.buyRateClamped,
      approx_sell_rate: rateRes.error ? null : rateRes.sellRate,
      is_economist: cons.is_economist,
    });
  }

  shortlistCandidates.sort((a, b) => {
    if (b.fit_score !== a.fit_score) return b.fit_score - a.fit_score;
    const aBuy = a.approx_buy_rate ?? Number.POSITIVE_INFINITY;
    const bBuy = b.approx_buy_rate ?? Number.POSITIVE_INFINITY;
    if (aBuy !== bBuy) return aBuy - bBuy;
    return String(a.name || "").localeCompare(String(b.name || ""));
  });

  const shortlist = shortlistCandidates.slice(0, SHORTLIST_SIZE);
  const top3 = shortlist.slice(0, TOPN_EXPOSED);

  const shortlistTop3Emails = top3.map((s) => s.email).join(", ");
  const shortlistTop3Names = top3.map((s) => s.name).join(", ");
  const shortlistTop3Scores = top3.map((s) => String(Math.round(s.fit_score))).join(", ");

  const shortlistStatus = shortlist.length > 0 ? "BUILT" : "NO_MATCH_FOUND";

  // ---- Selected consultant & transparent rate breakdown ----
  let consultantName = null;
  let consultantLevelId = null;
  let consultantLevelLabel = null;
  let consultantCurrency = null;
  let consultantFitScore = null;

  let consultantBuyRate = null;
  let consultantSellRate = null;
  let consultantBudgetTotal = null;

  let rateStatus = "NO_SELECTION";
  let rateError = null;

  // calc_* outputs
  const calc = {
    calc_base_min_rate: null,
    calc_base_max_rate: null,
    calc_base_suggested_rate: null,

    calc_role_scarcity_ids: parseCsv(role.role_scarcity_ids || "").join(", "),
    calc_consultant_scarcity_ids: null,
    calc_matched_scarcity_ids: null,
    calc_scarcity_uplift_mult: null,
    calc_scarcity_uplift_mult_capped: null,
    calc_scarcity_cap_applied: null,

    calc_client_buying_factor:
      role.client_buying_factor != null && role.client_buying_factor !== ""
        ? Number(role.client_buying_factor)
        : 1.0,
    calc_location_factor: 1.0,
    calc_margin_pct_default:
      role.client_default_margin != null && role.client_default_margin !== ""
        ? Number(role.client_default_margin)
        : 0.2,

    calc_buy_rate_raw: null,
    calc_buy_rate_clamped: null,
    calc_buy_rate_clamp_reason: null,

    calc_sell_rate: null,
    calc_days: role.role_days != null && role.role_days !== "" ? Number(role.role_days) : 0,
    calc_budget_buy_total: null,
    calc_budget_sell_total: null,
    calc_margin_abs: null,
    calc_margin_pct_realized: null,
  };

  if (consultantEmailRaw) {
    const key = consultantEmailRaw.toLowerCase();
    const selected = consultants.find((c) => c.email.toLowerCase() === key);

    if (!selected) {
      rateStatus = "ERROR";
      rateError = "Consultant not found in master sheet";
    } else {
      const fitRes = computeFitScore(role, selected);
      const rateRes = computeRateForPair(role, selected, scarcityConf);

      consultantName = selected.name;
      consultantLevelId = selected.level_id;
      consultantLevelLabel = selected.level_label;
      consultantCurrency =
        (selected.generic_rate_band && selected.generic_rate_band.currency) || "EUR";
      consultantFitScore = fitRes.score;

      // fill calc breakdown even if error (as far as possible)
      calc.calc_base_min_rate = rateRes.baseMin ?? null;
      calc.calc_base_max_rate = rateRes.baseMax ?? null;
      calc.calc_base_suggested_rate = rateRes.baseSuggested ?? null;

      calc.calc_consultant_scarcity_ids = (rateRes.consScIds || []).join(", ");
      calc.calc_matched_scarcity_ids = (rateRes.matchedScIds || []).join(", ");
      calc.calc_scarcity_uplift_mult = rateRes.scarcityUpliftMult ?? null;
      calc.calc_scarcity_uplift_mult_capped = rateRes.scarcityUpliftMultCapped ?? null;
      calc.calc_scarcity_cap_applied = rateRes.scarcityCapApplied ?? null;

      calc.calc_buy_rate_raw = rateRes.buyRateRaw ?? null;
      calc.calc_buy_rate_clamped = rateRes.buyRateClamped ?? null;
      calc.calc_buy_rate_clamp_reason = rateRes.buyRateClampReason ?? null;

      calc.calc_sell_rate = rateRes.sellRate ?? null;
      calc.calc_budget_buy_total = rateRes.budgetBuyTotal ?? null;
      calc.calc_budget_sell_total = rateRes.budgetSellTotal ?? null;
      calc.calc_margin_abs = rateRes.marginAbs ?? null;
      calc.calc_margin_pct_realized = rateRes.marginPctRealized ?? null;

      if (rateRes.error) {
        rateStatus = "ERROR";
        rateError = rateRes.error;
      } else {
        rateStatus = "CALCULATED";
        consultantBuyRate = rateRes.buyRateClamped;
        consultantSellRate = rateRes.sellRate;
        consultantBudgetTotal = rateRes.budgetSellTotal;
      }
    }
  }

  const debug = {
    consultant_email: consultantEmailRaw || null,
    has_selection: !!consultantEmailRaw,
    role,
    shortlist_size: shortlist.length,
    shortlist_preview: top3,
  };

  out.push({
    json: {
      rowNumber,

      shortlist_status: shortlistStatus,
      shortlist_top3_emails: shortlistTop3Emails,
      shortlist_top3_names: shortlistTop3Names,
      shortlist_top3_fit_scores: shortlistTop3Scores,
      shortlist_json: JSON.stringify(shortlist),

      consultant_name: consultantName,
      consultant_level_id: consultantLevelId,
      consultant_level_label: consultantLevelLabel,
      consultant_currency: consultantCurrency,
      consultant_fit_score: consultantFitScore,

      consultant_buy_rate: consultantBuyRate,
      consultant_sell_rate: consultantSellRate,
      consultant_budget_total: consultantBudgetTotal,
      rate_status: rateStatus,
      rate_error_message: rateError,
      rate_debug_json: JSON.stringify(debug),

      // ✅ IMPORTANT: this actually outputs the calc_* columns
      ...calc,
    },
  });
}

return out;

/**
 * FLOW 3 — Code in JavaScript1
 * Purpose (as you requested):
 * - Do NOT iterate over many items.
 * - Work ONLY on the single item produced by "Code in JavaScript2".
 * - Pass it through (optionally applying the cooldown).
 *
 * IMPORTANT:
 * - Your input example uses `shortlist_run_at`, but your old code checked `last_shortlist_run_at`.
 *   That mismatch is why it looked like it “should work” but then behaved unexpectedly in your flow.
 * - We accept BOTH field names and normalise to `last_shortlist_run_at` for downstream consistency.
 */

const MIN_MINUTES = 3;
const now = Date.now();

// Always take the single selected project from Code in JavaScript2
const p = $('Code in JavaScript2').first()?.json;
if (!p) {
  throw new Error('No input from "Code in JavaScript2". Make sure this node is connected after it.');
}

// status gate (keep if you use it; otherwise comment out)
if (String(p.status || 'ACTIVE').toUpperCase() !== 'ACTIVE') {
  return [];
}

// Normalise timestamps: support both shortlist_run_at and last_shortlist_run_at
const lastRun =
  p.last_shortlist_run_at ??
  p.shortlist_run_at ??
  null;

// Optional cooldown gate
if (lastRun) {
  const t = Date.parse(lastRun);
  if (!Number.isNaN(t)) {
    const diffMinutes = (now - t) / (1000 * 60);
    if (diffMinutes < MIN_MINUTES) {
      return [];
    }
  }
}

// sheet_id must exist and must be numeric (gid/tab id)
const sheet_id_raw = p.sheet_id ?? p.sheetId ?? null;
if (sheet_id_raw == null || sheet_id_raw === '') {
  throw new Error('Missing sheet_id on selected project.');
}

const sheet_id = String(sheet_id_raw).trim().replace(/^=+/, '').replace(/^gid=/i, '').replace(/^#/, '').trim();
if (!/^\d+$/.test(sheet_id)) {
  throw new Error(`Invalid sheet_id "${sheet_id_raw}". Expected a numeric tab id (gid).`);
}

return [
  {
    json: {
      ...p,
      sheet_id,                 // clean digits-only string
      last_shortlist_run_at: lastRun, // normalised field name
    },
  },
];

/**
 * FLOW 3 — Pick last project from Projects_Index
 *
 * Input:
 *  - Items from "Get Row(s)" on Projects_Index
 *
 * Output:
 *  - Exactly ONE item: the last row in the sheet
 *  - If sheet is empty → returns no items (flow stops cleanly)
 */

const items = $input.all();

if (!items || items.length === 0) {
  // No projects in index → nothing to process
  return [];
}

// Google Sheets returns rows in sheet order
// Last item = newest project
const lastItem = items[items.length - 1];

// Defensive copy + normalization
const row = lastItem.json || {};

const result = {
  project_id: row.project_id ?? null,
  project_name: row.project_name ?? null,
  file_id: row.file_id ?? null,
  sheet_id: row.sheet_id ?? row.sheetId ?? null,
  created_at: row.created_at ?? null,
  shortlist_run_at: row.shortlist_run_at ?? null,
};

if (!result.sheet_id) {
  throw new Error(
    'Projects_Index last row does not contain a valid sheet_id. Cannot continue.'
  );
}

return [
  {
    json: result,
  },
];
